import org.jetbrains.kotlin.resolve.ImportPath

fun main() {
    val layout = "*, |, javax.**, java.**, |, kotlinx.**, kotlin.**"
    val patterns = parseImportsLayout(layout)

    println("Patterns: $patterns")
    println()

    val imports = listOf(
        "java.nio.file.Files",
        "java.nio.file.Paths",
        "java.util.Objects"
    )

    val importSorter = ImportSorter(patterns)

    imports.forEach { import ->
        val importPath = ImportPath.fromString(import)
        val index = importSorter.findImportIndex(importPath)
        println("Import: $import, Index: $index")
    }

    println()
    println("Checking for blank lines between imports:")

    // Simulate the fold logic
    var prevIndex = -1
    imports.forEachIndexed { idx, import ->
        val importPath = ImportPath.fromString(import)
        val currentIndex = importSorter.findImportIndex(importPath)

        println("Import $idx: $import")
        println("  prevIndex: $prevIndex, currentIndex: $currentIndex")

        var hasBlankLines = false
        for (i in (prevIndex + 1) until currentIndex) {
            println("  Checking pattern[$i]: ${patterns[i]}")
            if (patterns[i] == PatternEntry.BLANK_LINE_ENTRY) {
                hasBlankLines = true
                println("  -> Found blank line at index $i")
                break
            }
        }

        if (hasBlankLines) {
            println("  -> Will insert blank line")
        }

        prevIndex = currentIndex
        println()
    }
}"}

